using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // [Fix 1] Discriminator property renamed: EF Core 9 defaults to "$type".
        // Preserve the old property name so existing documents are still found.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // [Fix 2] Id format changed: EF Core 9 uses just the key, not "Discriminator|Key".
        // Preserve the old "Blog|{Id}" format for existing documents.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasValueGenerator<BlogIdValueGenerator>();

        // [Fix 3] HasIndex throws at runtime on the Cosmos provider in EF Core 9.
        // Cosmos does not support secondary indexes via EF — removed the call.
        // (was: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);)
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

